/**
 * 将 data/*.json 合并为 js/data-bundle.js
 * 供 file:// 双击打开、Cursor 内置浏览器等无 fetch 环境使用
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.join(__dirname, '..');
const dataDir = path.join(root, 'data');
const reportsDir = path.join(dataDir, 'reports');
const out = path.join(root, 'js', 'data-bundle.js');

const companies = JSON.parse(fs.readFileSync(path.join(dataDir, 'companies.json'), 'utf8'));
const reports = {};
for (const c of companies.companies || []) {
  const p = path.join(reportsDir, `${c.id}.json`);
  if (!fs.existsSync(p)) {
    console.warn('skip missing report:', c.id);
    continue;
  }
  reports[c.id] = JSON.parse(fs.readFileSync(p, 'utf8'));
}

const body =
  '/* auto-generated by scripts/build-data-bundle.mjs — do not edit */\n' +
  'window.GUANDIAN_COMPANIES = ' +
  JSON.stringify(companies) +
  ';\n' +
  'window.GUANDIAN_REPORTS = ' +
  JSON.stringify(reports) +
  ';\n';

fs.writeFileSync(out, body, 'utf8');
const kb = (fs.statSync(out).size / 1024).toFixed(0);
console.log(`OK: ${out} (${Object.keys(reports).length} reports, ${kb} KB)`);
